mapper.select:
select appartinfo.id, appartinfo.name, appartinfo.introduction, appartinfo.district_id, appartinfo.district_name, appartinfo.city_id, appartinfo.city_name, appartinfo.province_id, appartinfo.province_name, appartinfo.address_detail, appartinfo.latitude, appartinfo.longitude, appartinfo.phone, appartinfo.is_release, coalesce(total_rooms.cnt,0) total_room_count, coalesce(total_rooms.cnt,0)-coalesce(rented_rooms.cnt,0) free_room_count from (select id, name, introduction, district_id, district_name, city_id, city_name, province_id, province_name, address_detail, latitude, longitude, phone, is_release from apartment_info
is_deleted=0
and province_id=#{queryVo.provinceId}
and city_id = #{queryVo.cityId}
and district_id = #{queryVo.districtId}
) appartinfo left join (select apartment_id, count(*) cnt from room_info where is_deleted = 0 and is_release = 1 group by apartment_id) total_rooms on appartinfo.id = total_rooms.apartment_id left join (select apartment_id, count(*) cnt from lease_agreement where is_deleted = 0 and status in (2, 5) group by apartment_id) rented_rooms on appartinfo.id = rented_rooms.apartment_id
